/**
 * SearchEngine — 全文检索引擎 (基于 minisearch 理念的轻量实现)
 *
 * 支持: 文本搜索、正则搜索、标签过滤、日期范围、文件夹过滤
 *
 * @see migration-map.md §4
 */
import type { SearchResult, SearchQuery, DocumentEntry, SearchMatch } from '@/types';

interface IndexedDoc {
  entry: DocumentEntry;
  content: string;
}

export class SearchEngine {
  private docs: Map<string, IndexedDoc> = new Map();
  private destroyed = false;

  buildIndex(documents: Record<string, DocumentEntry>): void {
    this.docs.clear();
    for (const [path, entry] of Object.entries(documents)) {
      this.docs.set(path, { entry, content: '' });
    }
  }

  async preloadContent(
    documents: Record<string, DocumentEntry>,
    contentProvider: (path: string) => Promise<string>,
  ): Promise<void> {
    for (const [path, entry] of Object.entries(documents)) {
      try {
        const content = await contentProvider(path);
        this.docs.set(path, { entry, content });
      } catch {
        this.docs.set(path, { entry, content: '' });
      }
    }
  }

  search(query: SearchQuery): SearchResult[] {
    if (this.destroyed) return [];

    let candidates: Array<{ path: string; doc: IndexedDoc }> = [...this.docs.entries()].map(
      ([path, doc]) => ({ path, doc }),
    );

    // Tag filter
    if (query.tags && query.tags.length > 0) {
      candidates = candidates.filter((c) =>
        query.tags!.some((t) => c.doc.entry.tags.some((dt) => dt.toLowerCase() === t.toLowerCase())),
      );
    }

    // Date range filter
    if (query.dateRange) {
      const { from, to } = query.dateRange;
      candidates = candidates.filter((c) => {
        const ts = c.doc.entry.created ?? 0;
        if (from && ts < from.getTime()) return false;
        if (to && ts > to.getTime()) return false;
        return true;
      });
    }

    // Folder filter
    if (query.folder && query.folder.length > 0) {
      candidates = candidates.filter((c) =>
        c.doc.entry.folder?.startsWith(query.folder!),
      );
    }

    // Regex search
    if (query.regex) {
      try {
        const re = new RegExp(query.regex, (query as any).regexFlags ?? 'gi');
        candidates = candidates.filter((c) => re.test(c.doc.content) || re.test(c.doc.entry.title));
      } catch {
        // invalid regex — skip regex filtering
      }
    }

    // Text search
    if (query.text && query.text.trim()) {
      const terms = query.text.trim().toLowerCase().split(/\s+/);
      const scored = candidates
        .map((c) => {
          let score = 0;
          const titleLC = c.doc.entry.title.toLowerCase();
          const contentLC = c.doc.content.toLowerCase();
          for (const term of terms) {
            if (titleLC.includes(term)) score += 10;
            const contentMatches = (contentLC.match(new RegExp(term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g')) || []).length;
            score += contentMatches;
          }
          return { ...c, score };
        })
        .filter((c) => c.score > 0)
        .sort((a, b) => b.score - a.score);

      return scored.map((c) => this.toResult(c.path, c.doc, query.text!, c.score));
    }

    // No text query — return all filtered candidates
    return candidates.map((c) => this.toResult(c.path, c.doc, '', 0));
  }

  private toResult(path: string, doc: IndexedDoc, queryText: string, score: number): SearchResult {
    const matches: SearchMatch[] = [];

    if (queryText && doc.content) {
      const queryLC = queryText.toLowerCase();
      const contentLC = doc.content.toLowerCase();
      const idx = contentLC.indexOf(queryLC);
      if (idx >= 0) {
        const start = Math.max(0, idx - 30);
        const end = Math.min(doc.content.length, idx + queryText.length + 30);
        const context =
          (start > 0 ? '…' : '') +
          doc.content.slice(start, end) +
          (end < doc.content.length ? '…' : '');

        matches.push({
          line: 0,
          column: idx,
          text: queryText,
          context,
        });
      }
    }

    return {
      notePath: path,
      noteTitle: doc.entry.title,
      matches,
      score,
    };
  }

  updateDocument(path: string, doc: DocumentEntry, content: string): void {
    this.docs.set(path, { entry: doc, content });
  }

  removeDocument(path: string): void {
    this.docs.delete(path);
  }

  destroy(): void {
    this.destroyed = true;
    this.docs.clear();
  }
}

/**
 * MarkdownPredictor 单元测试
 *
 * 覆盖：纯函数工具 / 语法上下文检测 / 结构化预测 / 融合决策 / 持久化与淘汰 / 边界与错误
 *
 * @see MarkdownPredictor.ts
 * @see spec/frontend/autocomplete-spec.md
 */
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { MarkdownPredictor } from '../MarkdownPredictor';
import type { PredictorIndexData } from '../MarkdownPredictor';
import { scanDocument, serialize, type NGramTable } from '@/utils/ngram-engine';

// ── 工具：通过 any 访问私有方法（仅用于纯函数算法验证） ──
function internals(p: MarkdownPredictor) {
  return p as any;
}

// ── Mock IndexData ──
function mockIndexData(overrides?: Partial<PredictorIndexData>): PredictorIndexData {
  return {
    getAllNoteTitles: () => ['快速入门', 'JavaScript笔记', '项目规划', 'API参考'],
    getAllTags: () => ['javascript', 'typescript', 'vue', 'react'],
    matchFilePaths: (prefix: string) => {
      const all = ['./notes/readme.md', './images/logo.png', './docs/api.md', './src/main.ts'];
      return all.filter((p) => p.startsWith(prefix));
    },
    ...overrides,
  };
}

// ── Mock localStorage ──
function mockLocalStorage(): Map<string, string> {
  const store = new Map<string, string>();
  vi.stubGlobal('localStorage', {
    getItem: vi.fn((k: string) => store.get(k) ?? null),
    setItem: vi.fn((k: string, v: string) => { store.set(k, v); }),
    removeItem: vi.fn((k: string) => { store.delete(k); }),
  });
  return store;
}

// ── Mock fetch ──
function mockFetch(responseText: string | null, ok = true) {
  vi.stubGlobal('fetch', vi.fn(async () => {
    if (!ok) throw new Error('Network error');
    return { ok, text: async () => responseText ?? '' };
  }));
}

// ============================================================================
// Step 2: 纯函数测试
// ============================================================================

describe('extractContext (private)', () => {
  it('正常截取光标前 n 个字符', () => {
    const p = new MarkdownPredictor(4);
    // cursorPos=10, n=4: start=6, 'Hello World!'.slice(6,10) = 'Worl'
    expect(internals(p).extractContext(10, 'Hello World!')).toBe('Worl');
  });

  it('光标位置 < n 时返回全部前缀', () => {
    const p = new MarkdownPredictor(4);
    expect(internals(p).extractContext(2, 'Hi')).toBe('Hi');
  });

  it('空文档返回空字符串', () => {
    const p = new MarkdownPredictor(4);
    expect(internals(p).extractContext(0, '')).toBe('');
  });
});

describe('getLineAt (private)', () => {
  it('行首位置', () => {
    const p = new MarkdownPredictor();
    const result = internals(p).getLineAt(0, 'line1\nline2\nline3');
    expect(result).toEqual({ text: 'line1', from: 0, to: 5 });
  });

  it('行中位置', () => {
    const p = new MarkdownPredictor();
    const result = internals(p).getLineAt(3, 'line1\nline2');
    expect(result).toEqual({ text: 'line1', from: 0, to: 5 });
  });

  it('最后一行', () => {
    const p = new MarkdownPredictor();
    const result = internals(p).getLineAt(10, 'line1\nline2');
    expect(result).toEqual({ text: 'line2', from: 6, to: 11 });
  });

  it('空文档', () => {
    const p = new MarkdownPredictor();
    const result = internals(p).getLineAt(0, '');
    expect(result).toEqual({ text: '', from: 0, to: 0 });
  });

  it('光标在换行符上 — 返回前一行的行', () => {
    const p = new MarkdownPredictor();
    // doc="hello\nworld": positions: h=0,e=1,l=2,l=3,o=4,\n=5,w=6,...
    // pos=5 is \n — getLineAt checks pos>=lineStart(0) && pos<=i+1(6) → returns "hello"
    const result = internals(p).getLineAt(5, 'hello\nworld');
    expect(result!.text).toBe('hello');
  });
});

describe('isInFencedCode (private)', () => {
  it('光标在代码块内 → true', () => {
    const p = new MarkdownPredictor();
    const doc = '```\ncode here\n```';
    expect(internals(p).isInFencedCode(5, doc)).toBe(true);
  });

  it('光标在代码块外 → false', () => {
    const p = new MarkdownPredictor();
    const doc = 'normal text\n```\ncode\n```\nmore text';
    expect(internals(p).isInFencedCode(2, doc)).toBe(false);
  });

  it('光标在代码块结束后 → false', () => {
    const p = new MarkdownPredictor();
    const doc = '```\ncode\n```\nafter';
    // "after" starts at position 12
    expect(internals(p).isInFencedCode(13, doc)).toBe(false);
  });

  it('嵌套 fence 标记 — 开关翻转', () => {
    const p = new MarkdownPredictor();
    const doc = '```\nouter\n```\nnot code\n```\ninner\n```';
    // Position in "not code" area
    expect(internals(p).isInFencedCode(14, doc)).toBe(false);
  });
});

describe('isInFrontmatter (private)', () => {
  it('光标在 frontmatter 内 → true', () => {
    const p = new MarkdownPredictor();
    const doc = '---\ntitle: test\ndate: 2026\n---\n\n# Content';
    expect(internals(p).isInFrontmatter(5, doc)).toBe(true);
  });

  it('光标在 frontmatter 外 → false', () => {
    const p = new MarkdownPredictor();
    const doc = '---\ntitle: test\n---\n\n# Content';
    expect(internals(p).isInFrontmatter(25, doc)).toBe(false);
  });

  it('无 frontmatter → false', () => {
    const p = new MarkdownPredictor();
    expect(internals(p).isInFrontmatter(5, '# Just a heading\nContent')).toBe(false);
  });

  it('未闭合的 frontmatter → false', () => {
    const p = new MarkdownPredictor();
    const doc = '---\ntitle: test\nno closing';
    expect(internals(p).isInFrontmatter(3, doc)).toBe(false);
  });
});

describe('detectOpenFormat (private)', () => {
  it('** 未闭合 → 返回 **', () => {
    const p = new MarkdownPredictor();
    // line "**bold text", cursor at end (col 11)
    expect(internals(p).detectOpenFormat('**bold text', 11)).toBe('**');
  });

  it('** 已闭合 → 不返回', () => {
    const p = new MarkdownPredictor();
    expect(internals(p).detectOpenFormat('**bold** text', 8)).toBeNull();
  });

  it('` 未闭合 → 返回 `', () => {
    const p = new MarkdownPredictor();
    expect(internals(p).detectOpenFormat('`code text', 10)).toBe('`');
  });

  it('` 已闭合 → 不返回', () => {
    const p = new MarkdownPredictor();
    expect(internals(p).detectOpenFormat('`code`', 6)).toBeNull();
  });

  it('无任何标记 → null', () => {
    const p = new MarkdownPredictor();
    expect(internals(p).detectOpenFormat('plain text', 10)).toBeNull();
  });
});

// ============================================================================
// detectSyntaxContext (public) & isDisabledContext (public)
// ============================================================================

describe('detectSyntaxContext', () => {
  let p: MarkdownPredictor;

  beforeEach(() => { p = new MarkdownPredictor(4); });

  it('[[ 内 → wiki-link', () => {
    const doc = '参考 [[快速入';
    const ctx = p.detectSyntaxContext(9, doc);
    expect(ctx.type).toBe('wiki-link');
    expect(ctx.prefix).toBe('快速入');
  });

  it('[[空前缀 → wiki-link with empty prefix', () => {
    const doc = '参考 [['; // cursor at position 5
    const ctx = p.detectSyntaxContext(5, doc);
    expect(ctx.type).toBe('wiki-link');
    expect(ctx.prefix).toBe('');
  });

  it('#tag → tag type', () => {
    const doc = 'tags: #java';
    const ctx = p.detectSyntaxContext(11, doc);
    expect(ctx.type).toBe('tag');
    expect(ctx.prefix).toBe('java');
  });

  it('行首 #tag → tag type', () => {
    const doc = '#tag';
    const ctx = p.detectSyntaxContext(4, doc);
    expect(ctx.type).toBe('tag');
  });

  it('标题 # 不应识别为 tag', () => {
    const doc = '# Heading';
    const ctx = p.detectSyntaxContext(2, doc);
    expect(ctx.type).toBe('general');
  });

  it('[text](path → file-path type', () => {
    const doc = '[link](./note';
    const ctx = p.detectSyntaxContext(13, doc);
    expect(ctx.type).toBe('file-path');
    expect(ctx.prefix).toBe('./note');
  });

  it('![alt](path → file-path type', () => {
    const doc = '![img](./pic';
    const ctx = p.detectSyntaxContext(12, doc);
    expect(ctx.type).toBe('file-path');
  });

  it('未闭合 ** → markdown-format', () => {
    const doc = '**bold text';
    const ctx = p.detectSyntaxContext(11, doc);
    expect(ctx.type).toBe('markdown-format');
    expect(ctx.openMarker).toBe('**');
  });

  it('普通段落 → general', () => {
    const doc = '这是一段普通文字';
    const ctx = p.detectSyntaxContext(4, doc);
    expect(ctx.type).toBe('general');
  });

  it('空文档 → general', () => {
    const ctx = p.detectSyntaxContext(0, '');
    expect(ctx.type).toBe('general');
  });
});

describe('isDisabledContext', () => {
  let p: MarkdownPredictor;

  beforeEach(() => { p = new MarkdownPredictor(4); });

  it('代码块内 → true', () => {
    const doc = '```\ncode\n```';
    expect(p.isDisabledContext(4, doc)).toBe(true);
  });

  it('frontmatter 内 → true', () => {
    const doc = '---\ntitle: x\n---\n\nbody';
    expect(p.isDisabledContext(5, doc)).toBe(true);
  });

  it('空行 → true (empty doc)', () => {
    // getLineAt(0,'') returns {text:'',from:0,to:0}, text.trim()==='' → true
    expect(p.isDisabledContext(0, '')).toBe(true);
  });

  it('正常段落 → false', () => {
    const doc = '# Hello\n\nWorld';
    expect(p.isDisabledContext(2, doc)).toBe(false);
  });
});

// ============================================================================
// Step 3: 结构化预测 (通过 getGhostText + mock indexData)
// ============================================================================

describe('结构化预测 — Wiki-link', () => {
  let p: MarkdownPredictor;

  beforeEach(() => {
    p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
  });

  it('精确匹配 → 高置信度补全', () => {
    // 输入 "[[快速入" → "门" → complete to "门]]"
    const result = p.getGhostText(8, '参考 [[快速入');
    expect(result).not.toBeNull();
    expect(result!.text).toContain(']]');
    expect(result!.confidence).toBeGreaterThanOrEqual(0.75);
  });

  it('前缀匹配 → 返回最短匹配', () => {
    // "[[J" 应匹配 "JavaScript笔记" — cursor at end of 'see [[J' (len=7)
    const result = p.getGhostText(7, 'see [[J');
    expect(result).not.toBeNull();
    expect(result!.text).toContain('avaScript笔记]]');
  });

  it('无匹配 → null', () => {
    const result = p.getGhostText(5, 'see [[zz');
    expect(result).toBeNull();
  });
});

describe('结构化预测 — Tag', () => {
  let p: MarkdownPredictor;

  beforeEach(() => {
    p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
  });

  it('#ja → 补全 javascript', () => {
    // 'tags: #ja'.length = 9, cursor at end
    const result = p.getGhostText(9, 'tags: #ja');
    expect(result).not.toBeNull();
    if (result) {
      expect(result.text).toContain('va');
    }
  });

  it('#re → 精确匹配 react', () => {
    // 'framework: #re'.length = 14, cursor at end
    const result = p.getGhostText(14, 'framework: #re');
    expect(result).not.toBeNull();
    if (result) {
      expect(result.text).toContain('ac');
    }
  });
});

describe('结构化预测 — File Path', () => {
  let p: MarkdownPredictor;

  beforeEach(() => {
    p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
  });

  it('[text](./n → 补全路径', () => {
    const result = p.getGhostText(15, '[readme](./note');
    expect(result).not.toBeNull();
    if (result) {
      expect(result.text).toContain('s/readme.md)');
    }
  });

  it('无匹配路径 → 退回到 n-gram', () => {
    const result = p.getGhostText(14, '[file](./xyz');
    // May return null or n-gram, but should not crash
    expect(result === null || result !== null).toBe(true);
  });
});

describe('结构化预测 — Format Closure', () => {
  let p: MarkdownPredictor;

  beforeEach(() => {
    p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
  });

  it('**粗 → 闭合 **', () => {
    // '**粗体'.length = 4 (2 ASCII + 2 中文 = 4 JS chars), cursor at end
    const result = p.getGhostText(4, '**粗体');
    expect(result).not.toBeNull();
    if (result) {
      expect(result.text).toBe('**');
      expect(result.source).toBe('structured');
      expect(result.syntaxType).toBe('markdown-format');
      expect(result.confidence).toBeGreaterThanOrEqual(0.8);
    }
  });

  it('裸 ** 显示占位补全（BUG-A01 修复：避免 N-gram 接管）', () => {
    const result = p.getGhostText(2, '**');
    expect(result).not.toBeNull();
    expect(result!.text).toBe('粗体**');
    expect(result!.confidence).toBeGreaterThan(0.8);
  });

  it('*斜 → 闭合 * (hasPrefix, confidence 0.88 > 0.8, 返回闭合标记)', () => {
    const result = p.getGhostText(4, 'a*斜体');
    // hasPrefix → 只返回闭合标记 `*`, 不重复 prefix
    expect(result).not.toBeNull();
    expect(result!.text).toBe('*');
  });

  it('`代码 → 闭合 ` (confidence 0.85 > 0.8)', () => {
    // '`代码' has only 3 chars < n=4; pad to 'a`代码' with cursor at end
    const result = p.getGhostText(4, 'a`代码');
    expect(result).not.toBeNull();
    if (result) {
      expect(result.text).toContain('`');
    }
  });

  it('**闭合** 后不重复闭合', () => {
    // '**闭合**'.length = 6, cursor at end
    const result = p.getGhostText(6, '**闭合**');
    // If detectOpenFormat returns null (even count), getGhostText may return
    // n-gram prediction or null — but NOT another ** closure
    if (result && result.confidence > 0.8) {
      expect(result.text).not.toContain('粗体**');
    }
  });

  it('格式闭合不需要 indexData (Defect 1 修复验证)', () => {
    // BUG-029: predictFormatClosure 不应被 indexData guard 阻断
    const p2 = new MarkdownPredictor(4);
    // 故意不调用 setIndexData — indexData 为 null
    const result = p2.getGhostText(4, '**粗体');
    expect(result).not.toBeNull();
    expect(result!.text).toBe('**');
    expect(result!.source).toBe('structured');
    expect(result!.syntaxType).toBe('markdown-format');
    expect(result!.confidence).toBeGreaterThanOrEqual(0.8);
  });
});

// ============================================================================
// Step 4: 融合决策测试
// ============================================================================

describe('getGhostText — 融合决策', () => {
  it('结构化高置信度 (>0.8) → 优先返回结构化', () => {
    const p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
    // "[[快速入" → wiki-link with confidence 0.95
    const result = p.getGhostText(8, '参考 [[快速入');
    expect(result).not.toBeNull();
    expect(result!.confidence).toBeGreaterThan(0.8);
  });

  it('结构化低置信度 (<0.8) + N-gram 高置信度 → 返回 N-gram', () => {
    // Train L1 with a repeating pattern so N-gram has high confidence
    const p = new MarkdownPredictor(4);
    // Provide indexData with many titles → wiki-link confidence drops to 0.75
    p.setIndexData(mockIndexData({
      getAllNoteTitles: () => ['testAAA', 'testAAB', 'testAAC'],
    }));
    // Scan a doc with the pattern "test test test" multiple times
    const doc = 'test test test test test test test test test test';
    p.scanOpenedDocument(doc);
    // Now query with "test tes" (cursor at end, 8 chars) — N-gram should predict "t"
    const result = p.getGhostText(8, 'test tes');
    // N-gram should have a prediction from L1 (the "test" pattern)
    expect(result).not.toBeNull();
  });

  it('仅结构化有效 → 返回结构化', () => {
    const p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
    // Empty L1/L2, only structured knowledge available
    const result = p.getGhostText(7, 'tag: #ja');
    expect(result).not.toBeNull();
    // Since L1/L2 are empty, structured prediction should surface
  });

  it('禁用上下文 → 返回 null', () => {
    const p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
    const result = p.getGhostText(4, '```\n#ja');
    expect(result).toBeNull();
  });

  it('上下文不足 (< n chars) → 返回 null', () => {
    const p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());
    const result = p.getGhostText(1, 'a');
    expect(result).toBeNull();
  });
});

describe('getGhostText — L1/L2 优先级', () => {
  it('L1 和 L2 都有预测时取置信度高者', () => {
    const p = new MarkdownPredictor(4);
    // Train L1 with specific pattern
    p.scanOpenedDocument('为了解决问题\n为了解决问题\n为了解决问题\n为了解决');
    // L2 is empty, so only L1 available
    const result = p.getGhostText(16, '为了解决');
    if (result) {
      expect(result.confidence).toBeGreaterThanOrEqual(0.15);
    }
  });
});

// ============================================================================
// Step 5: 持久化与淘汰
// ============================================================================

describe('saveToLocalStorage + loadFromLocalStorage', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it('round-trip: 保存后重新加载 → 数据一致', async () => {
    mockLocalStorage();
    const p = new MarkdownPredictor(4);
    p.setIndexData(mockIndexData());

    // Scan a document with high repetition to survive pruneTable(minCount=3)
    // Each n-gram context→prediction pair must appear ≥3 times
    p.scanOpenedDocument('test test test test test test test test test test test test');
    p.closeDocument();

    // Now create a new predictor and load
    const p2 = new MarkdownPredictor(4);
    // Access private loadFromLocalStorage
    internals(p2).loadFromLocalStorage();
    const l2 = internals(p2).l2 as NGramTable;

    expect(l2.size).toBeGreaterThan(0);
  });

  it('空 L2 保存不崩溃', () => {
    mockLocalStorage();
